solve(Points) ->
    N = length(Points),
    if N < 4 -> 0;
       true ->
            AllCombinations = combinations(4, Points),
            count_trapezoids(AllCombinations, 0)
    end.

combinations(0, _, Acc) -> Acc;
combinations(K, [H|T], Acc) ->
    combinations(K-1, T, [H | Acc]) ++ combinations(K, T, Acc);
combinations(_, [], _) -> [].

combinations(K, List) when K > length(List) -> [];
combinations(K, List) -> combinations(K, List, []).

count_trapezoids([], Count) -> Count;
count_trapezoids([Quad | Rest], Count) ->
    case is_trapezoid(Quad) of
        true -> count_trapezoids(Rest, Count + 1);
        false -> count_trapezoids(Rest, Count)
    end.

is_trapezoid([P1, P2, P3, P4]) ->
    Slopes = [
        {slope(P1, P2), slope(P3, P4)},
        {slope(P1, P3), slope(P2, P4)},
        {slope(P1, P4), slope(P2, P3)}
    ],
    lists:any(fun({S1, S2}) -> parallel(S1, S2) end, Slopes).

slope([X1, Y1], [X2, Y2]) ->
    case X2 - X1 of
        0 -> infinity;
        DX -> (Y2 - Y1) / DX
    end.

parallel(infinity, infinity) -> true;
parallel(S1, S2) when is_number(S1), is_number(S2) -> abs(S1 - S2) < 1.0e-10;
parallel(_, _) -> false.
